import React, { createContext, useState, useEffect } from 'react';
import axios from 'axios';

// Create context
const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Check if user is logged in on initial load
  useEffect(() => {
    const checkLoggedIn = async () => {
      // Check if token exists in local storage
      const token = localStorage.getItem('token');

      if (token) {
        // Load user data - Version simplifiée
        const loadUser = async () => {
          if (localStorage.token) {
            setAuthToken(localStorage.token);
          } else {
            return; // Pas de token, pas besoin de charger l'utilisateur
          }

          try {
            // URL directe sans préfixe /api
            const res = await axios.get('/users/profile/');
            setUser(res.data);
            setIsAuthenticated(true);
          } catch (err) {
            console.error('Erreur de chargement utilisateur:', err);
            localStorage.removeItem('token'); // Supprimer le token invalide
            setUser(null);
            setIsAuthenticated(false);
          }
        };

        loadUser();
      } else {
        setLoading(false);
      }
    };

    checkLoggedIn();
  }, []);

  // Set auth token for axios
  const setAuthToken = (token) => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  };

  // Register user - Version simplifiée
  const register = async (userData) => {
    try {
      console.log('Tentative d\'inscription avec:', userData);
      setError(null);

      // URL directe sans préfixe /api
      const res = await axios.post('/users/register/', {
        username: userData.username,
        email: userData.email,
        password: userData.password,
        password2: userData.password2,
        bio: userData.bio || ''
      });

      console.log('Réponse d\'inscription:', res.data);
      alert('Inscription réussie!');
      window.location.href = '/login';
      return res.data;
    } catch (err) {
      console.error('Erreur d\'inscription:', err);
      let message = 'L\'inscription a échoué';

      if (err.response?.data) {
        if (typeof err.response.data === 'object') {
          // Simplifier le message d'erreur
          message = Object.keys(err.response.data)
            .map(key => `${key}: ${err.response.data[key]}`)
            .join(', ');
        } else {
          message = err.response.data;
        }
      }

      setError(message);
      alert('Erreur: ' + message);
    }
  };

  // Login user - Version simplifiée
  const login = async (userData) => {
    try {
      console.log('Tentative de connexion avec:', userData);
      setError(null);

      // URL directe sans préfixe /api
      const res = await axios.post('/token/', {
        email: userData.email,
        password: userData.password
      });

      console.log('Réponse de connexion:', res.data);

      // Save token to local storage
      localStorage.setItem('token', res.data.access);

      // Set auth token in headers
      setAuthToken(res.data.access);

      // Get user data
      try {
        const userRes = await axios.get('/users/profile/');
        console.log('Données utilisateur:', userRes.data);
        setUser(userRes.data);
        setIsAuthenticated(true);
        setError(null);

        alert('Connexion réussie!');
        window.location.href = '/';
      } catch (profileErr) {
        console.error('Erreur profil:', profileErr);
        setIsAuthenticated(true);
        alert('Connexion réussie!');
        window.location.href = '/';
      }

      return res.data;
    } catch (err) {
      console.error('Erreur de connexion:', err);
      let message = 'Échec de connexion';

      if (err.response?.data) {
        if (typeof err.response.data === 'object') {
          if (err.response.data.detail) {
            message = err.response.data.detail;
          } else {
            // Simplifier le message d'erreur
            message = Object.keys(err.response.data)
              .map(key => `${key}: ${err.response.data[key]}`)
              .join(', ');
          }
        } else {
          message = err.response.data;
        }
      }

      setError(message);
      alert('Erreur: ' + message);
    }
  };

  // Logout user
  const logout = () => {
    // Remove token from local storage
    localStorage.removeItem('token');

    // Remove auth token from headers
    setAuthToken(null);

    // Reset state
    setUser(null);
    setIsAuthenticated(false);
  };

  // Update user profile
  const updateProfile = async (userData) => {
    try {
      const res = await axios.put('/users/me/', userData);
      setUser(res.data);
      return res.data;
    } catch (err) {
      setError(err.response?.data?.detail || 'Profile update failed');
      throw err;
    }
  };

  // Clear errors
  const clearError = () => {
    setError(null);
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated,
        loading,
        error,
        register,
        login,
        logout,
        updateProfile,
        clearError
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

// Export context for use in components
AuthContext.displayName = 'AuthContext';
AuthProvider.context = AuthContext;
export default AuthContext;
